const data = $input.first().json;
const events = data['@graph'] || [];

const today = new Date();
today.setHours(0, 0, 0, 0);

const concerts = events.filter(e => {
  const type = e['@type'] || '';
  const title = e['title'] || '';
  if (!type.includes('Música') && !type.includes('Concierto') && !title.toLowerCase().includes('concierto')) {
      return false;
  }
  if (!e.dtstart) return false;
  const eventDate = new Date(e.dtstart);
  return eventDate >= today;
});

concerts.sort((a, b) => new Date(a.dtstart) - new Date(b.dtstart));
const topConcerts = concerts.slice(0, 10);
if (topConcerts.length === 0) return [];

let listaDatos = [];
topConcerts.forEach(c => {
  const date = c.dtstart ? c.dtstart.split(' ')[0] : 'Sin fecha';
  const time = c.time || 'Sin hora';
  let location = c['event-location'] || '';
  if (!location && c.organization && c.organization['organization-name']) {
      location = c.organization['organization-name'];
  }
  if (!location) location = 'Verificar en web oficial';

  listaDatos.push({
      titulo: c.title,
      fecha: date,
      hora: time,
      lugar: location
  });
});

return [{ json: { mensaje: JSON.stringify(listaDatos, null, 2) } }];

const item = $input.first();
let textoCompleto;

try {
  const data = item.json;
  // Groq usa 'choices' igual que OpenAI
  if (data && data.choices && data.choices.length > 0) {
    textoCompleto = data.choices[0].message.content;
  } else {
    return [{ json: { mensaje: "Error: Groq no devolvió texto." } }];
  }
} catch (e) {
  return [{ json: { mensaje: "Error procesando la respuesta de Groq." } }];
}

return [{
  json: {
    mensaje: textoCompleto
  }
}];

